#include <stdio.h>
#include <stdint.h>

// Define register structure
typedef struct {
    uint32_t PC;      // Program Counter
    uint32_t IR;      // Instruction Register
    uint32_t MAR;     // Memory Address Register
    uint32_t MDR;     // Memory Data Register
    uint32_t ACC;     // Accumulator
    uint32_t status;  // Status flags
} CPURegisters;

// Instruction opcodes
#define OP_LOAD  0x01
#define OP_STORE 0x02
#define OP_ADD   0x03
#define OP_JUMP  0x04

// Extract opcode from instruction
uint8_t get_opcode(uint32_t instruction) {
    return (instruction >> 24) & 0xFF;
}

// Extract address from instruction
uint32_t get_address(uint32_t instruction) {
    return instruction & 0x00FFFFFF;
}

// Execute instruction
void execute(CPURegisters *cpu, uint32_t *memory) {
    uint8_t opcode = get_opcode(cpu->IR);
    uint32_t address = get_address(cpu->IR);

    switch(opcode) {
        case OP_LOAD:
            cpu->MAR = address;
            cpu->MDR = memory[cpu->MAR];
            cpu->ACC = cpu->MDR;
            break;

        case OP_STORE:
            cpu->MAR = address;
            cpu->MDR = cpu->ACC;
            memory[cpu->MAR] = cpu->MDR;
            break;

        case OP_ADD:
            cpu->MAR = address;
            cpu->MDR = memory[cpu->MAR];
            cpu->ACC += cpu->MDR;
            break;

        case OP_JUMP:
            cpu->PC = address;
            break;
    }
}

int main() {
    CPURegisters cpu = {0};
    uint32_t memory[256] = {0};

    // Setup: memory[10] = 50
    memory[10] = 50;

    // LOAD instruction at address 0
    memory[0] = (OP_LOAD << 24) | 10;

    // Fetch
    cpu.MAR = cpu.PC;
    cpu.IR = memory[cpu.MAR];
    cpu.PC++;

    // Execute
    execute(&cpu, memory);

    printf("Accumulator = %u\n", cpu.ACC);
    return 0;
}
